const items = $input.all();
const results = [];

for (const item of items) {
  const tw = item.json.body || item.json;
  const from = tw.From || '';
  const name = tw.ProfileName || 'User';
  const body = tw.Body || '';

  if (!body) {
    results.push({ json: { _skip: true } });
    continue;
  }

  const prompt = 'You are Digital Clone, a helpful AI. Be concise.\n\nUser (' + name + ') says: "' + body + '"\n\nReply in plain text, under 300 characters.';

  results.push({
    json: {
      _prompt: prompt,
      _from: from,
      _to: tw.To || ''
    }
  });
}

return results;

const items = $input.all();
const results = [];
for (const item of items) {
  if (!item.json._skip) results.push(item);
}
return results;

const items = $input.all();
const results = [];
const promptNode = $('Build Prompt');

for (let i = 0; i < items.length; i++) {
  const d = items[i].json;
  const orig = promptNode ? promptNode.item.json : {};
  const raw = d.response || '';
  const reply = String(raw).trim().substring(0, 1500) || 'I received your message.';
  const from = d._from || orig._from || '';
  const to = d._to || orig._to || '';

  results.push({
    json: { _reply: reply, _from: from, _to: to }
  });
}

return results;
